func Test_ImageMetadataOnly(t *testing.T) {
	// JPEG image to validate metadata extraction without OCR.
	var config kreuzberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"disable_ocr":true,"ocr":null}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := kreuzberg.ExtractFile(`images/example.jpg`, nil, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if strings.TrimSpace(result.MimeType) != `image/jpeg` {
		t.Errorf("equals mismatch: got %v", result.MimeType)
	}
	assert.LessOrEqual(t, len(result.Content), 200, "expected length <= 200")
}

func Test_ImageSvgBasic(t *testing.T) {
	// SVG image extraction.
	result, err := kreuzberg.ExtractFile(`xml/simple_svg.svg`, nil, kreuzberg.ExtractionConfig{})
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if strings.TrimSpace(result.MimeType) != `image/svg+xml` {
		t.Errorf("equals mismatch: got %v", result.MimeType)
	}
	assert.GreaterOrEqual(t, len(result.Content), 5, "expected length >= 5")
}
